class Solution {
    public int minimizedStringLength(String s) {
        boolean[] charSet = new boolean[26];
        for (char c : s.toCharArray()) {
            charSet[c - 'a'] = true;
        }
        int count = 0;
        for (boolean b : charSet) {
            if (b) count++;
        }
        return count;
    }
}
```
